def _render_svg(svg_str, size, color=None):
    """Rend un SVG en QPixmap avec la couleur donnée."""
    c = color or QColor(255, 255, 255)
    color_hex = c.name()
    svg = svg_str.replace("{color}", color_hex)

    key = hashlib.md5(f"{svg}{size}".encode()).hexdigest()
    cache_path = os.path.join(_CACHE_DIR, f"{key}.png")

    if os.path.exists(cache_path):
        px = QPixmap(cache_path)
        if not px.isNull():
            return px

    data = QByteArray(svg.encode("utf-8"))
    renderer = QSvgRenderer(data)

    px = QPixmap(size, size)
    px.fill(Qt.transparent)
    p = QPainter(px)
    p.setRenderHint(QPainter.Antialiasing)
    renderer.render(p)
    p.end()

    px.save(cache_path)
    return px


def get_pixmap(name, size=24, color=None):
    svg = _SVG_DATA.get(name)
    if svg:
        return _render_svg(svg, size, color)
    # Fallback
    px = QPixmap(size, size)
    px.fill(Qt.transparent)
    p = QPainter(px)
    p.setPen(QColor(255, 255, 255, 120))
    p.setFont(QFont("Segoe UI", max(6, size // 3)))
    p.drawText(QRectF(0, 0, size, size), Qt.AlignCenter, name[:3])
    p.end()
    return px


def get_icon(name, size=24, color=None):
    return QIcon(get_pixmap(name, size, color))


def get_file_icon(filename, size=20):
    ext = filename.rsplit(".", 1)[-1].lower() if "." in filename else ""
    mapping = {
        "py": ("python", QColor(80, 160, 255)),
        "cpp": ("cplusplus", QColor(80, 160, 255)),
        "js": ("file", QColor(255, 220, 50)),
        "html": ("globe", QColor(255, 100, 50)),
        "css": ("file", QColor(50, 150, 255)),
        "json": ("file", QColor(255, 180, 50)),
        "md": ("notepad", QColor(100, 180, 255)),
        "txt": ("file", QColor(200, 200, 200)),
        "jpg": ("image", None),
        "jpeg": ("image", None),
        "png": ("image", None),
        "gif": ("image", None),
        "svg": ("image", None),
        "mp3": ("music", None),
        "wav": ("music", None),
        "mp4": ("video", None),
        "avi": ("video", None),
        "url": ("link", QColor(0, 120, 215)),
        "webloc": ("link", QColor(0, 120, 215)),
        "lnk": ("chevron_right", QColor(150, 150, 150)),
        "obj": ("file", QColor(255, 140, 0)),
        "stl": ("file", QColor(255, 140, 0)),
        "glb": ("file", QColor(255, 140, 0)),
        "pdf": ("pdf", QColor(220, 50, 50)),
        "zip": ("folder", QColor(255, 200, 50)),
        "rar": ("folder", QColor(255, 200, 50)),
        "exe": ("settings", QColor(100, 200, 255)),
    }
    icon_name, color = mapping.get(ext, ("file", QColor(200, 200, 200)))
    return get_icon(icon_name, size, color)